# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

def send_reset_email(email, token):
    reset_link = f"http://localhost:5000/reset_password?token={token}"
    msg = MIMEText(f"Click the link to reset your password: {reset_link}")
    msg['Subject'] = 'Password Reset'
    msg['From'] = 'noreply@example.com'
    msg['To'] = email

    with smtplib.SMTP('localhost') as server:
        server.send_message(msg)

def store_token(email, token):
    conn = sqlite3.connect('database.db')
    c = conn.cursor()
    c.execute("CREATE TABLE IF NOT EXISTS password_resets (email TEXT, token TEXT)")
    c.execute("INSERT INTO password_resets (email, token) VALUES (?, ?)", (email, token))
    conn.commit()
    conn.close()

@app.route('/reset_password', methods=['POST'])
def reset_password():
    email = request.json.get('email')
    token = secrets.token_urlsafe(16)
    store_token(email, token)
    send_reset_email(email, token)
    return jsonify({"message": "Reset link sent to your email"}), 200

if __name__ == '__main__':
    app.run(debug=True)